import React, { useState } from "react";
import "./InternalPortal.css";

function InternalPortal() {

  const [jobs] = useState([
    {
      id: 1,
      title: "Frontend Engineer",
      company: "Abhishyandh Global Solutions",
      location: "Hyderabad",
      skills: ["React", "Redux", "MUI"],
      description: "Build scalable UI systems using React"
    },
    {
      id: 2,
      title: "Backend Node.js Developer",
      company: "Abhishyandh Global Solutions",
      location: "Hyderabad",
      skills: ["Node.js", "Express", "MongoDB"],
      description: "Develop backend APIs"
    }
  ]);

  const [selectedJob, setSelectedJob] = useState(null);

  return (
    <div className="internal-container">

      <h2>Internal Job Portal</h2>

      {/* Stats Cards */}

      <div className="job-stats">

        <div className="stat-card">
          <h3>2</h3>
          <p>Open Positions</p>
        </div>

        <div className="stat-card">
          <h3>0</h3>
          <p>Total Applicants</p>
        </div>

        <div className="stat-card">
          <h3>0</h3>
          <p>Your Applications</p>
        </div>

      </div>


      {/* Search */}

      <input
        type="text"
        placeholder="Search jobs"
        className="job-search"
      />


      {/* Job Cards */}

      <div className="job-list">

        {jobs.map((job) => (

          <div
            key={job.id}
            className="job-card"
            onClick={() => setSelectedJob(job)}
          >

            <h3>{job.title}</h3>

            <p>
              {job.company} • {job.location}
            </p>

            <div className="skills">

              {job.skills.map((skill, index) => (

                <span key={index}>{skill}</span>

              ))}

            </div>

          </div>

        ))}

      </div>


      {/* Job Modal */}

      {selectedJob && (

        <div className="job-modal">

          <div className="modal-content">

            <button
              className="close-btn"
              onClick={() => setSelectedJob(null)}
            >
              X
            </button>

            <h2>{selectedJob.title}</h2>

            <p>{selectedJob.description}</p>

          </div>

        </div>

      )}

    </div>
  );
}

export default InternalPortal;
